#include<bits/stdc++.h>
using namespace std;
const int maxn = 5005;
long long n,k,m,a[maxn],dp[maxn][maxn],que[maxn],ans=-0x3f3f3f3f;
int main()
{
	cin>>n>>k>>m; 
	for(int i=1;i<=n;i++)cin>>a[i];
	memset(dp,-0x3f,sizeof(dp));
	dp[0][0]=0;
	for(int j=1;j<=m;j++)
	{
		que[0]=0;
		int l=0,r=1;
		for(int i=1;i<=n;i++)
		{
			while(l<r&&que[l]<i-k)l++;
			dp[i][j]=dp[que[l]][j-1]+a[i];
			while(l<r&&dp[que[r-1]][j-1]<=dp[i][j-1])r--;
			que[r++]=i;
		}
	}
	for(int i=n-k+1;i<=n;i++)ans=max(ans,dp[i][m]);
	if(ans<0)cout<<-1;
	else cout<<ans;
	return 0;
}
